const STORIES = [
  // ─── Kolay (15) ──────────────────────────────────────────────────────────
  {id:1,title:'A New Start in the City',level:'Kolay',
   text:'Maria was very {nervous} on her first day at the new {office} in the city center. She woke up early to prepare a {healthy} {breakfast} of fruit and yogurt. She wore her best blue {dress} and took the {bus} because she wanted to save {money}. When she arrived, she saw a very tall {building} with many glass windows. Her new {boss}, Mr. Miller, was a very {friendly} man. He smiled and said "Welcome to the {team}!" Maria felt very {happy} because she worked hard to get this {job}. She met her new colleagues and they were all very {kind} to her. It was an {exciting} day for her.',
   options:['nervous','office','healthy','breakfast','dress','bus','money','building','boss','friendly','team','happy','job','kind','exciting','sad','lazy','train','dinner']},
  {id:2,title:'The Mystery of the Missing Key',level:'Kolay',
   text:'Tom could not find his {key} this morning, and he was very {worried}. He looked in every {room} of his small house. He looked under the wooden {table}, behind the heavy {door}, and even inside the {fridge} next to the {milk}. "Where is it?" he asked himself. Then he remembered. He looked inside his jacket {pocket} and felt something {metal}. Finally, he found it! He was a bit {late} for his {work} at the {market}, but he was glad to have his keys. He locked the {door} and ran to his {car} as fast as he could.',
   options:['key','worried','room','table','door','fridge','milk','pocket','metal','late','work','market','car','window','bag','sleep','early']},
  {id:3,title:'Anna\'s Special Birthday',level:'Kolay',
   text:'Today is Anna\'s tenth {birthday} and she is very {excited}. Her {family} wanted to make it a special {day} for her. They decorated the large living room with colorful {balloons} and beautiful {flowers} from the {garden}. Her mother spent all morning in the {kitchen} baking a delicious chocolate {cake}. They sang a happy {song} together when the sun went down. Anna received many {presents} from her friends, including a new {book} about space and a cute {toy}. She felt like a {princess} and thanked everyone for the {surprise}.',
   options:['birthday','excited','family','day','balloons','flowers','garden','kitchen','cake','song','presents','book','toy','princess','surprise','sad','work','school']},
  {id:4,title:'The Secret Garden Discovery',level:'Kolay',
   text:'Mary lives in a big {house} with a beautiful {garden}. Every morning, she puts on her {shoes} and goes outside to enjoy the {fresh} air. She loves to see the colorful {flowers} and the tall green {trees}. One day, she found a small wooden {door} hidden behind some thick bushes. It was the {door} to a secret {garden}! Inside, she saw many {birds} singing and {butterflies} flying around the {water}. She felt very {excited} and {happy}. She decided to keep the {garden} a secret and visit it every {day} after {school}. It became her favorite {place} to {read} her {books} and {relax}.',
   options:['house','garden','shoes','fresh','flowers','trees','door','birds','butterflies','water','excited','happy','day','school','place','read','books','relax','work','city','busy']},
  {id:5,title:'A Rainy Day at Home',level:'Kolay',
   text:'It was raining outside all day long, so Ben decided to stay {home}. He wanted to {relax} and stay {warm}. He read an interesting {book} about animals and made a hot cup of {tea}. He listened to the sound of {rain} on the window and felt very {peaceful}. Later, he watched a {film} on the {television} with his {cat}. His cat was very {sleepy} and stayed on his lap. Even though it was {cloudy} outside, Ben had a very {good} day inside his {house}.',
   options:['home','relax','warm','book','tea','rain','peaceful','film','television','cat','sleepy','cloudy','good','house','coffee','music','noisy']},

  // ─── Orta (15) ───────────────────────────────────────────────────────────
  {id:11,title:'The Meticulous Interview',level:'Orta',
   text:'David arrived at the corporate {office} ten minutes early to ensure he made a good first {impression}. He had prepared for the {interview} {meticulous}ly by researching the company\'s history and its recent {innovative} projects. The {manager} greeted him warmly and asked several {challenging} questions about his previous experience and technical {skills}. David answered with {confidence} and demonstrated his ability to {collaborate} with a diverse {team}. He felt a strong sense of {achievement} when the manager praised his {diligent} preparation and his clear {communication}. By the end of the meeting, David was very {optimistic} about the {position} and the future {growth} of the company.',
   options:['office','impression','interview','meticulous','innovative','manager','challenging','skills','confidence','collaborate','team','achievement','diligent','communication','optimistic','position','growth','lazy','failure']},
  {id:12,title:'Resilience in Travel',level:'Orta',
   text:'At the airport, Sophie discovered her {flight} was {cancelled} due to {unprecedented} weather conditions and heavy {snow}. This unexpected {adversity} was a big {challenge} for her vacation plans. She had to find a new {accommodation} for the night and find a way to {mitigate} the impact on her tight schedule. The airline was {responsible} for the delay and provided her with a {voucher} for a nearby hotel and a {free} dinner. Despite the initial {frustration}, Sophie remained {resilient}. She decided to explore the {vibrant} city center during her unexpected {stay}. She visited a local {museum} and enjoyed a {delicious} meal, making the most of her {transition} period between cities.',
   options:['flight','cancelled','unprecedented','snow','adversity','challenge','accommodation','mitigate','responsible','voucher','free','frustration','resilient','vibrant','stay','museum','delicious','transition','cheap','boring']},
  {id:13,title:'The Transition to Remote Work',level:'Orta',
   text:'In recent years, the global workforce has seen an {unprecedented} {transition} toward {remote} work. Many companies have realized that employees can be highly {productive} and {diligent} without being present in a traditional {office} every day. This shift has several {advantages}, such as increased {flexibility} and significantly reduced {commuting} time. However, it also presents unique {challenges}, like social {isolation} and the difficulty of separating {work} from personal {life}. To {succeed} in this new {environment}, teams must {collaborate} effectively using digital {tools} and maintain a high level of {communication}. The {consensus} among many experts is that a {hybrid} model will become the permanent {standard} for many {industries} in the near {future}.',
   options:['unprecedented','transition','remote','productive','diligent','office','advantages','flexibility','commuting','challenges','isolation','work','life','succeed','environment','collaborate','tools','communication','consensus','hybrid','standard','industries','future','lazy','manual']},
  {id:14,title:'A Comprehensive Approach to Health',level:'Orta',
   text:'Dr. Kim advised her {patient} to adopt a {comprehensive} approach to their {health}. She suggested eating a balanced {diet} full of {vegetables} and exercising for at least thirty minutes a day to {alleviate} stress. She explained that good {nutrition} reduces the risk of chronic {diseases} significantly. Staying {active} is {imperative} for maintaining both physical and mental {well-being}. Dr. Kim also emphasized the importance of {sleep}, explaining that it helps the brain {function} properly and allows the body to {recover}. By following this {diligent} plan, the patient could expect a {tangible} improvement in their overall {energy} levels.',
   options:['patient','comprehensive','health','diet','vegetables','alleviate','nutrition','diseases','active','imperative','well-being','sleep','function','recover','diligent','tangible','energy','lazy','sick']},
  {id:15,title:'Cultural Exchange and Traditions',level:'Orta',
   text:'During the cultural {exchange} programme, students from ten different countries shared their unique {traditions} and stories. They cooked traditional {dishes} from their homelands and discussed their diverse {customs} in a {vibrant} atmosphere. This experience helped them {understand} different {perspectives} and build strong {international} friendships. The {foster}ing of mutual respect was a key part of the event. Many students realized that despite their {differences}, they shared many {intrinsic} values. The event was a great {success} and the organizers hope to {reconcile} any cultural {discrepancies} through future collaborative projects.',
   options:['exchange','traditions','dishes','customs','vibrant','understand','perspectives','international','foster','differences','intrinsic','success','reconcile','discrepancies','collaborate','festival','culture','local']},

  // ─── İleri (15) ──────────────────────────────────────────────────────────
  {id:21,title:'The Ethical Scrutiny of AI',level:'İleri',
   text:'As artificial {intelligence} continues to evolve at an {unprecedented} rate, our {society} must grapple with profound {ethical} dilemmas that were once confined to science fiction. The primary {concern} revolves around the {accountability} of autonomous systems, especially when they produce {unintended} or {detrimental} consequences in critical fields like medicine or law. Furthermore, the {pervasive} nature of {algorithmic} bias threatens to {exacerbate} existing social {inequalities} if left unchecked by human {scrutiny}. It is {imperative} that we establish robust {legislation} and {foster} a culture of transparency to ensure that technology remains a force for {good}. We must also {mitigate} the risk of certain skills becoming {obsolete} while promoting a global {consensus} on international safety standards. The {paradox} of AI is that while it offers the potential for {abundance}, it also demands {meticulous} oversight to prevent systemic {adversity}.',
   options:['intelligence','unprecedented','society','ethical','concern','accountability','unintended','detrimental','pervasive','algorithmic','exacerbate','inequalities','scrutiny','imperative','legislation','foster','good','mitigate','obsolete','consensus','paradox','abundance','meticulous','adversity','simple','neutral']},
  {id:22,title:'Climate Change and Global Sustainability',level:'İleri',
   text:'Scientific {consensus} suggests that without immediate and significant {intervention}, global {temperatures} will rise to catastrophic levels, leading to {unprecedented} environmental {adversity}. Governments worldwide must {collaborate} to adopt {innovative} and {renewable} energy policies while implementing strict {regulations} on carbon {emissions} to {mitigate} the greenhouse effect. The preservation of {biodiversity} is {imperative} for the long-term health of our planet\'s {ecosystems}. We must {transition} to a sustainable economic {model} that prioritizes {sustainability} over short-term financial {profits}. This shift requires {meticulous} planning and a {resilient} approach to the {fluctuate}ing global climate. Only through {unilateral} and multilateral cooperation can we {alleviate} the pressure on our natural {resources}. The {implications} of failing to act are {imminent} and potentially {detrimental} to all of {humanity}.',
   options:['consensus','intervention','temperatures','unprecedented','adversity','collaborate','innovative','renewable','regulations','emissions','mitigate','biodiversity','imperative','ecosystems','transition','model','sustainability','profits','meticulous','resilient','fluctuate','unilateral','alleviate','resources','implications','imminent','detrimental','humanity','ignore','static']},
  {id:23,title:'The Geopolitics of Space Exploration',level:'İleri',
   text:'The rapid {acceleration} of space {exploration} has sparked a new era of {geopolitical} competition and {unprecedented} scientific {breakthroughs}. As private corporations and national space agencies {collaborate} on ambitious missions to Mars, the {implications} for international {sovereignty} become increasingly complex and {ambiguous}. The potential {extraction} of lunar {resources} and the establishment of permanent bases on celestial bodies raise significant {ethical} and {legal} {conundrums}. It is {imperative} that we establish a global {framework} to prevent planetary {contamination} and ensure that the benefits of space technology are shared fairly. Without such a {consensus}, the risk of {conflict} and environmental {adversity} in the final {frontier} will {exacerbate} existing global {tensions}. We must {mitigate} these risks through {meticulous} diplomacy and {innovative} policy-making, ensuring that the {pinnacle} of human achievement does not lead to {detrimental} outcomes for our home planet.',
   options:['acceleration','exploration','geopolitical','unprecedented','breakthroughs','collaborate','implications','sovereignty','ambiguous','extraction','resources','ethical','legal','conundrums','imperative','framework','contamination','consensus','conflict','adversity','frontier','exacerbate','tensions','mitigate','meticulous','innovative','pinnacle','detrimental','simple','static']},
  {id:24,title:'The Paradox of Modern Choice',level:'İleri',
   text:'Modern consumers are often {overwhelmed} by an {abundance} of options in every {aspect} of their daily lives. While having {freedom} of choice is generally {perceived} as a positive {intrinsic} value, research suggests that too many {alternatives} can lead to {anxiety} and decision {paralysis}. This {phenomenon} often results in {dissatisfaction} with the final {selection}, as individuals worry about the {opportunity} cost of the options they rejected. This is the {paradox} of choice: an {abundance} of options can actually {inhibit} our ability to feel {happy} with our decisions. To {mitigate} this effect, some people are moving toward a more {minimalist} lifestyle, seeking to {alleviate} the mental {burden} of constant {scrutiny} over small decisions. They believe that by reducing the number of choices, they can {foster} a more {vibrant} and {resilient} sense of {well-being}.',
   options:['overwhelmed','abundance','aspect','freedom','perceived','intrinsic','alternatives','anxiety','paralysis','phenomenon','dissatisfaction','selection','opportunity','paradox','inhibit','happy','mitigate','minimalist','alleviate','burden','scrutiny','foster','vibrant','resilient','well-being','easy','sad']},
  {id:25,title:'Sustainable Urbanization and Infrastructure',level:'İleri',
   text:'The rapid {migration} of populations to urban centers {necessitates} a complete {reimagining} of city {infrastructure} and {architectural} design. To achieve true {sustainability}, we must {integrate} green spaces, efficient public {transit}, and {renewable} energy systems into the very fabric of our cities. Failing to {address} the environmental {footprint} of urban areas will lead to {unprecedented} social and {ecological} crises in the coming decades. It is {imperative} that city planners {collaborate} with scientists to {mitigate} the effects of urban heat islands and {alleviate} the pressure on local {resources}. This requires {innovative} thinking and a {comprehensive} {transition} away from {obsolete} urban models. The {pinnacle} of modern {urbanization} should be the creation of {vibrant}, {resilient} communities that {foster} a high quality of life for all residents while protecting the {intrinsic} beauty of the natural {environment}.',
   options:['migration','necessitates','reimagining','infrastructure','architectural','sustainability','integrate','transit','renewable','address','footprint','unprecedented','ecological','imperative','collaborate','mitigate','alleviate','resources','innovative','comprehensive','transition','obsolete','pinnacle','urbanization','vibrant','resilient','foster','intrinsic','environment','build','small']},

  {id:101,title:'The Morning Walk',level:'Kolay',
   text:'Every morning, David puts on his {shoes} and goes for a walk in the {park}. He likes to feel the {fresh} air on his face. He sees many {birds} in the {trees} and sometimes he sees a little {dog} running on the grass. Walking makes him feel {happy} and gives him {energy} for the {day}. He always takes a bottle of {water} with him.',
   options:['shoes','park','fresh','birds','trees','dog','happy','energy','day','water','cat','sad','night']},
  {id:102,title:'Baking Cookies',level:'Kolay',
   text:'Sarah decided to bake some chocolate {cookies} for her {family}. She went to the {kitchen} and found some {flour}, {sugar}, and {eggs}. She mixed everything in a big {bowl}. After twenty {minutes} in the {oven}, the cookies were ready. The {smell} was wonderful. Her {brother} ate three cookies and smiled.',
   options:['cookies','family','kitchen','flour','sugar','eggs','bowl','minutes','oven','smell','brother','salt','car']},
  {id:103,title:'A Visit to the Zoo',level:'Kolay',
   text:'The school organized a trip to the city {zoo}. The children were very {excited} to see the {animals}. They saw a huge {elephant} eating leaves and a tall {giraffe} stretching its neck. The monkeys were very {funny} because they were jumping around. At the end of the {day}, everyone was {tired} but very {happy}.',
   options:['zoo','excited','animals','elephant','giraffe','funny','day','tired','happy','sad','school','car']},
  {id:104,title:'The Lost Cat',level:'Kolay',
   text:'Emily could not find her little {cat}, Luna. She looked under the {bed} and behind the {sofa}. She walked into the {garden} and called her name. Suddenly, she heard a soft {sound} coming from the {tree}. Luna was sitting on a branch, looking {scared}. Emily climbed up and saved her. She felt very {relieved}.',
   options:['cat','bed','sofa','garden','sound','tree','scared','relieved','dog','happy','kitchen']},
  {id:105,title:'A Day at the Beach',level:'Kolay',
   text:'During the {summer}, Mark loves to visit the {beach}. The yellow {sand} is very hot, so he runs to the {water} quickly. He likes to swim in the cold {sea} and collect small {shells}. In the afternoon, he eats a cold {ice} cream and watches the {sun} go down. It is his favorite {season}.',
   options:['summer','beach','sand','water','sea','shells','ice','sun','season','winter','snow']},
  {id:106,title:'Shopping for Clothes',level:'Kolay',
   text:'Lisa needs a new {dress} for a party. She goes to the {shopping} center with her {friend}. They look at many different {clothes} in the {store}. Lisa tries on a red dress, but it is too {small}. Then she finds a beautiful blue dress that fits perfectly. She pays with her {money} and leaves the store feeling {great}.',
   options:['dress','shopping','friend','clothes','store','small','money','great','shoes','bad','car']},
  {id:201,title:'The New Smartphone',level:'Orta',
   text:'Tech companies are constantly releasing {innovative} devices. Yesterday, I bought a new {smartphone} that has an incredible {camera} and a very fast {processor}. The {battery} life is also much better than my old phone. However, the {price} was quite high, which made me hesitate initially. Technology evolves so fast that it is difficult to {maintain} the latest {gadgets} without spending a lot of {money}.',
   options:['innovative','smartphone','camera','processor','battery','price','maintain','gadgets','money','cheap','slow']},
  {id:202,title:'Learning to Play Guitar',level:'Orta',
   text:'Learning a new {instrument} requires a lot of {patience} and daily {practice}. When John first bought his acoustic {guitar}, his fingers hurt and the sounds were {terrible}. But he was {determined} to succeed. He watched online {tutorials} and practiced basic {chords} every evening. After three {months}, he could finally play his favorite {song} smoothly. His {dedication} had paid off.',
   options:['instrument','patience','practice','guitar','terrible','determined','tutorials','chords','months','song','dedication','lazy','easy']},
  {id:203,title:'The Importance of Recycling',level:'Orta',
   text:'Our city has started a new {campaign} to encourage {recycling} among residents. We produce too much {waste}, and our local {landfills} are becoming completely full. By separating {plastic}, {paper}, and {glass}, we can significantly {reduce} our environmental {footprint}. The local {government} has provided special {bins} for every household. It is a small {effort} that creates a massive {impact} on our planet.',
   options:['campaign','recycling','waste','landfills','plastic','paper','glass','reduce','footprint','government','bins','effort','impact','increase','pollution']},
  {id:204,title:'A Weekend Hike',level:'Orta',
   text:'To escape the {stress} of the busy city, a group of {friends} decided to go {hiking} in the mountains. They packed their {backpacks} with snacks, {water}, and a {map}. The trail was quite {steep} and physically {demanding}, but the fresh {breeze} kept them cool. When they reached the {summit}, the panoramic {view} was absolutely {breathtaking}. The {experience} brought them closer together.',
   options:['stress','friends','hiking','backpacks','water','map','steep','demanding','breeze','summit','view','breathtaking','experience','easy','boring']},
  {id:205,title:'Starting a Healthy Routine',level:'Orta',
   text:'Many people struggle to {maintain} a healthy {lifestyle} because of their demanding {jobs}. Emily decided to change her {habits} by waking up an hour {earlier} to do some {yoga}. She also started preparing her own {meals} instead of ordering fast {food}. Initially, it was a huge {challenge} to resist sweet {snacks}, but soon she noticed a {significant} increase in her daily {energy}.',
   options:['maintain','lifestyle','jobs','habits','earlier','yoga','meals','food','challenge','snacks','significant','energy','lazy','decrease']},
  {id:206,title:'The Local Library',level:'Orta',
   text:'Despite the rise of {digital} media, the local {library} remains a vital {resource} for our {community}. It is a {peaceful} sanctuary where students can study without {distractions}. The library offers a vast {collection} of literature, from classic {novels} to modern {biographies}. The helpful {librarians} are always ready to {assist} visitors in finding the exact {information} they need.',
   options:['digital','library','resource','community','peaceful','distractions','collection','novels','biographies','librarians','assist','information','noisy','internet']},
  {id:301,title:'The Philosophy of Stoicism',level:'İleri',
   text:'Stoicism is an ancient Greek {philosophy} that emphasizes the development of self-control and {fortitude} as a means of overcoming destructive {emotions}. The core {tenet} is that we cannot control external {events}, only our {reactions} to them. By accepting the {inevitable} nature of the universe, practitioners seek to achieve a state of mental {tranquility}. This {pragmatic} approach to life helps individuals {navigate} modern {adversity} with grace and {resilience}, proving that historical {wisdom} remains highly {relevant} today.',
   options:['philosophy','fortitude','emotions','tenet','events','reactions','inevitable','tranquility','pragmatic','navigate','adversity','resilience','wisdom','relevant','panic','weakness']},
  {id:302,title:'Advances in Biotechnology',level:'İleri',
   text:'The recent {acceleration} in {biotechnology} research has led to {unprecedented} medical {breakthroughs}. CRISPR gene editing, for example, offers the {potential} to eradicate hereditary {diseases} by precisely {modifying} DNA sequences. However, this immense power brings profound {ethical} dilemmas regarding genetic {enhancement} and human {modification}. The scientific {community} must establish stringent {regulations} to prevent {unintended} consequences while fostering {innovation}. Balancing progress with {moral} responsibility is the ultimate {conundrum} of our era.',
   options:['acceleration','biotechnology','unprecedented','breakthroughs','potential','diseases','modifying','ethical','enhancement','modification','community','regulations','unintended','innovation','moral','conundrum','static','simple']},
  {id:303,title:'The Impact of Microplastics',level:'İleri',
   text:'The {ubiquitous} presence of {microplastics} in global {ecosystems} constitutes a severe environmental {crisis}. These microscopic synthetic {polymers} have infiltrated the deepest {oceans} and the highest mountain {peaks}. Scientific {investigations} reveal that marine {organisms} ingest these particles, which eventually {accumulate} in the human food chain. The long-term {toxicological} effects on human {physiology} remain largely {ambiguous}, necessitating urgent and {comprehensive} research to {mitigate} this invisible {threat}.',
   options:['ubiquitous','microplastics','ecosystems','crisis','polymers','oceans','peaks','investigations','organisms','accumulate','toxicological','physiology','ambiguous','comprehensive','mitigate','threat','clean','safe']},
  {id:304,title:'Cognitive Dissonance',level:'İleri',
   text:'In psychology, cognitive {dissonance} refers to the mental {discomfort} experienced by someone who holds two or more {contradictory} beliefs or values. When confronted with new {information} that clashes with existing {paradigms}, individuals often employ {defense} mechanisms to reduce the {psychological} stress. They might {rationalize} their behavior or entirely {dismiss} the conflicting {evidence}. Understanding this {phenomenon} is crucial for analyzing how {propaganda} and political {rhetoric} can effectively {manipulate} public {opinion}.',
   options:['dissonance','discomfort','contradictory','information','paradigms','defense','psychological','rationalize','dismiss','evidence','phenomenon','propaganda','rhetoric','manipulate','opinion','harmony','truth']},
  {id:305,title:'The Architecture of Tomorrow',level:'İleri',
   text:'Contemporary {architecture} is undergoing a paradigm {shift} towards {sustainability} and ecological {integration}. Architects are now {incorporating} biomimicry into their {designs}, creating structures that {mimic} biological processes to regulate {temperature} and manage {resources} efficiently. The use of {renewable} materials and the integration of vertical {gardens} aim to {alleviate} the carbon {footprint} of urban {sprawl}. This holistic {approach} ensures that future cities will not only be {aesthetically} pleasing but also environmentally {resilient}.',
   options:['architecture','shift','sustainability','integration','incorporating','designs','mimic','temperature','resources','renewable','gardens','alleviate','footprint','sprawl','approach','aesthetically','resilient','obsolete','ugly']},
  {id:306,title:'The Economics of Automation',level:'İleri',
   text:'The widespread {implementation} of {automation} and artificial {intelligence} in manufacturing is fundamentally {disrupting} traditional labor {markets}. While these technologies exponentially increase {productivity} and reduce operational {costs}, they also render many manual {occupations} entirely {obsolete}. Economists warn that this {transition} could {exacerbate} income {inequality} if governments fail to implement adequate {retraining} programs. A proactive {strategy} involving universal basic income or robust social {safety} nets might be {imperative} to prevent widespread economic {disenfranchisement}.',
   options:['implementation','automation','intelligence','disrupting','markets','productivity','costs','occupations','obsolete','transition','exacerbate','inequality','retraining','strategy','safety','imperative','disenfranchisement','stable','wealth']},

 {id:107,title:"Tom's Bicycle",level:'Kolay',
  text:'Tom has a new {bicycle}. He {rides} it every morning before school. His father {taught} him how to ride last {summer}. Tom always wears a {helmet} to stay safe. He loves to go down the big {hill} near his house. One day, he found a {shortcut} through the park. Now he arrives at school five minutes {early}. His friends think his bicycle is very {cool}.',
  options:['bicycle','rides','taught','summer','helmet','hill','shortcut','early','cool','bus','late','winter','scared','walk']},

 {id:108,title:'The Lost Dog',level:'Kolay',
  text:'One rainy afternoon, a small {dog} appeared at the door of Emma\'s house. It was wet and {shivering}. Emma gave it some {food} and a warm {blanket}. She checked the dog\'s {collar} and found a phone number. She {called} the owner right away. The owner was very {relieved} to hear his dog was safe. He came to pick up the dog and thanked Emma {warmly}. Emma felt happy that she had {helped}.',
  options:['dog','shivering','food','blanket','collar','called','relieved','warmly','helped','cat','ignored','cold','scared','hungry']},

 {id:109,title:'The Library',level:'Kolay',
  text:'Sara loves going to the {library} after school. She always sits at her favourite {table} near the window. Today she is reading a book about {dolphins}. The librarian, Mrs. Green, helps her find the best {books}. Sara {borrowed} three books this week. She makes notes in a small {notebook} as she reads. Her dream is to become a {writer} one day. The library makes her feel {calm} and inspired.',
  options:['library','table','dolphins','books','borrowed','notebook','writer','calm','noisy','bored','teacher','tired','bench','return']},

 {id:110,title:'A Kind Neighbour',level:'Kolay',
  text:'Old Mr. Hassan lives alone next door. Every Saturday, young Ali {visits} him and helps with the {garden}. They plant {flowers} and water the vegetables together. Mr. Hassan tells Ali {stories} about his life when he was young. Ali listens {carefully} and learns many things. One day, Ali brought him a homemade {cake}. Mr. Hassan was very {touched}. He said that Ali was like a {grandson} to him. Their {friendship} makes both of them happy.',
  options:['visits','garden','flowers','stories','carefully','cake','touched','grandson','friendship','ignored','selfish','angry','stranger','weeds']},

 {id:111,title:'The Football Match',level:'Kolay',
  text:'It was the day of the big {match}. Leo and his team were nervous but {excited}. The {coach} gave them a short speech before the game. In the first half, the score was zero to zero. Then Leo {passed} the ball to his friend Marco, who {scored} the winning {goal}. Everyone {cheered} and ran onto the pitch. It was the best day of Leo\'s {life}.',
  options:['match','excited','coach','passed','scored','goal','cheered','life','lost','angry','alone','referee','practice','tired']},

 {id:112,title:'A Day at the Beach',level:'Kolay',
  text:'The family drove to the {beach} on a sunny Saturday. The children ran straight into the {sea}. Mum {spread} a big towel on the sand and relaxed. Dad {built} a sandcastle with the youngest child. They ate sandwiches and cold drinks for {lunch}. In the afternoon, they {collected} shells along the shore. As the sun began to set, they packed their things and {headed} home. Everyone agreed it was a {perfect} day.',
  options:['beach','sea','spread','built','lunch','collected','headed','perfect','stayed','cloudy','mountain','forest','dinner','crowded']},

 {id:113,title:'The Camping Trip',level:'Kolay',
  text:'Every year, Mia\'s family goes {camping} in the mountains. They pitch a tent beside a {stream}. In the morning, they wake up early and cook {breakfast} on a small fire. Mia loves to {explore} the forest trails with her older {brother}. They sometimes spot deer and rabbits. At night, they sit around the fire and tell {stories}. Mia always falls asleep looking at the {stars}. She says camping is her favourite {holiday}.',
  options:['camping','stream','breakfast','explore','brother','stories','stars','holiday','boring','city','sister','evening','lunch','hotel']},

 {id:207,title:'A Fresh Start',level:'Orta',
  text:'After losing her job, Maria decided to open her own small {business}. It was a {risk}, but she had always dreamed of running a café. She found a suitable {location} in the town centre and signed a {lease}. The first few months were {challenging}. She had to manage the finances, hire {staff}, and attract new {customers}. She began offering free Wi-Fi and locally sourced {ingredients}. Word spread quickly, and the café became very {popular}. Maria realised that sometimes failure is the beginning of something {better}.',
  options:['business','risk','location','lease','challenging','staff','customers','ingredients','popular','better','quit','easy','profit','closed']},

 {id:208,title:'Moving to a New City',level:'Orta',
  text:'When James moved to the city for work, he knew {nobody} there. He rented a small {apartment} and explored the neighbourhood on foot. At first, he felt quite {lonely}. He {joined} a local running club to meet people. Gradually, he started making friends. He {discovered} a fantastic market every Sunday where he bought fresh produce. He also found a café where he could work {remotely}. Six months later, the city felt like {home}. James realised that stepping out of your {comfort} zone can be truly {rewarding}.',
  options:['nobody','apartment','lonely','joined','discovered','remotely','home','comfort','rewarding','stayed','afraid','familiar','isolated','empty']},

 {id:209,title:'Language Exchange',level:'Orta',
  text:'Fatima wanted to improve her English, so she joined an online language {exchange} programme. She was paired with Sophie, a student from Canada who was learning {Arabic}. They spoke for one hour in English, then one hour in Arabic. At first, the {conversations} were simple and sometimes {awkward}. But over time, they began discussing everything from food to {politics}. They also shared recipes and music {recommendations}. Fatima\'s English {improved} rapidly, and Sophie\'s Arabic became {stronger}. Language had brought them {together}.',
  options:['exchange','Arabic','conversations','awkward','politics','recommendations','improved','stronger','together','failed','silent','apart','refused','boring']},

 {id:210,title:'Finding Balance',level:'Orta',
  text:'David was a dedicated software {engineer} who worked long hours every day. He rarely exercised and often skipped meals. After a routine {checkup}, his doctor warned him that his lifestyle was {unsustainable}. David decided to make {changes}. He started waking up thirty minutes earlier to go for a walk. He began cooking simple, healthy meals at home. He also set strict {boundaries} around work hours. Within a few months, he felt more {energetic} and less {stressed}. He learned that {productivity} depends on wellbeing, not just hard work.',
  options:['engineer','checkup','unsustainable','changes','boundaries','energetic','stressed','productivity','lazy','ignored','balanced','exhausted','illness','stable']},

 {id:211,title:'The Photography Club',level:'Orta',
  text:'Nina had always been passionate about {photography} but never had the confidence to share her work. A friend suggested she join the school photography {club}. At the first meeting, she was surprised by how {friendly} everyone was. The club organised monthly photo {walks} around the city. Nina began experimenting with light and {composition}. Her mentor {encouraged} her to enter a national {competition}. She did not win, but her photo was {selected} for an exhibition. Seeing her work on a gallery wall changed something in her. She stopped doubting herself and started {creating} boldly.',
  options:['photography','club','friendly','walks','composition','encouraged','competition','selected','creating','afraid','hidden','ignored','rejected','alone']},

 {id:212,title:'Volunteering Abroad',level:'Orta',
  text:'After finishing university, Tom chose to spend six months {volunteering} in East Africa. He taught mathematics at a rural {primary} school. The conditions were basic, with no electricity and limited {supplies}. But the children\'s {enthusiasm} for learning was extraordinary. Tom had to {adapt} his teaching methods and rely on {creativity} rather than technology. He also learned valuable lessons about {resilience} and community. The experience changed his {perspective} on education. When he returned home, he founded a charity to support rural schools. He says it was the most {meaningful} thing he has ever done.',
  options:['volunteering','primary','supplies','enthusiasm','adapt','creativity','resilience','perspective','meaningful','comfortable','ignored','refused','simple','distant']},

 {id:213,title:'Running a Marathon',level:'Orta',
  text:'When Aisha first decided to run a marathon, she could barely jog for ten minutes without stopping. She followed a sixteen-week {training} plan. Every morning she got up at six to run. Some days she felt strong; other days she {struggled}. She {pushed} through knee pain and bad weather. On race day, the {atmosphere} was electric. Thousands of runners lined up together. At mile twenty, Aisha hit what runners call the {wall}. She slowed down but did not stop. She crossed the finish {line} in four hours. Tears ran down her face. She had proved something to {herself}.',
  options:['training','struggled','pushed','atmosphere','wall','line','herself','quit','weak','failed','coach','distance','speed','record']},

 {id:307,title:'The Neuroscience of Habit',level:'İleri',
  text:'Habits are encoded in a region of the brain called the basal ganglia, which operates largely beneath conscious {awareness}. When a behaviour is repeated consistently, neural {pathways} are strengthened through a process known as {myelination}. This makes the behaviour progressively more {automatic}, requiring less cognitive {effort}. Research identifies a three-part {loop}: a cue that triggers the routine, the routine itself, and the {reward} that reinforces it. Understanding this {mechanism} enables individuals to {deliberately} replace harmful habits with {constructive} ones. The key insight is that habits are never truly deleted — they are only {overwritten} by new associations, making long-term {consistency} absolutely essential.',
  options:['awareness','pathways','myelination','automatic','effort','loop','reward','mechanism','deliberately','constructive','overwritten','consistency','random','forgotten','passive','instant']},

 {id:308,title:'Globalisation and Identity',level:'İleri',
  text:'Globalisation has facilitated an unprecedented {exchange} of goods, ideas, and cultures, yet it has simultaneously {provoked} anxieties about the {erosion} of local identities. As multinational {corporations} homogenise consumer behaviour through global {branding}, distinct regional traditions risk becoming commercially {diluted}. Critics argue that economic {interdependence} can {subordinate} cultural {sovereignty} to market imperatives. However, others contend that globalisation also enables {marginalised} communities to amplify their {voices} on an international stage. The challenge for contemporary societies is to embrace the benefits of interconnectedness without {sacrificing} the cultural {diversity} that enriches human {civilisation}.',
  options:['exchange','provoked','erosion','corporations','branding','diluted','interdependence','subordinate','sovereignty','marginalised','voices','sacrificing','diversity','civilisation','isolated','uniform','rejected','fading']},

 {id:309,title:'The Psychology of Creativity',level:'İleri',
  text:'Creativity is commonly {romanticised} as a spontaneous flash of inspiration, yet psychological research reveals a far more structured process. Teresa Amabile\'s model identifies three critical elements: domain-relevant {skills}, creativity-relevant processes, and intrinsic {motivation}. The latter is particularly significant: studies consistently show that external {rewards} can paradoxically {undermine} creative output by shifting focus from internal {satisfaction} to external {validation}. The neuroscientific concept of the {default} mode network further explains how relaxed, unfocused mental states {facilitate} associative thinking. Organisations that {cultivate} psychological {safety} — where employees feel free to experiment without fear of {judgement} — consistently generate more innovative {outcomes}.',
  options:['romanticised','skills','motivation','rewards','undermine','satisfaction','validation','default','facilitate','cultivate','safety','judgement','outcomes','forced','fearful','blocked','rigid','suppressed']},

 {id:310,title:'Clean Energy Solutions',level:'İleri',
  text:'The global {transition} to clean energy represents one of the most complex and consequential {undertakings} of the twenty-first century. Solar and wind technologies have seen dramatic cost {reductions} over the past decade, making them increasingly {competitive} with fossil fuels. Nevertheless, the {intermittent} nature of renewable energy generation necessitates substantial {investment} in grid-scale {storage} solutions. Advanced batteries and emerging hydrogen fuel cell technology are being explored as potential {remedies}. Simultaneously, the decommissioning of carbon-intensive {infrastructure} poses significant economic and social {challenges}, particularly for communities historically {dependent} on coal and oil. A just and {equitable} energy transition requires coordinated international {cooperation} and long-term political {commitment}.',
  options:['transition','undertakings','reductions','competitive','intermittent','investment','storage','remedies','infrastructure','challenges','dependent','equitable','cooperation','commitment','instant','simple','unlimited','passive']},

 {id:311,title:'Digital Literacy',level:'İleri',
  text:'In an era of pervasive digital media, the ability to critically {evaluate} information has become an indispensable civic {competency}. Research found that students at all levels struggled to {distinguish} sponsored content from {legitimate} journalism and to assess the credibility of social media sources. The proliferation of algorithmically curated newsfeeds creates epistemic {bubbles} that {reinforce} existing beliefs while systematically {excluding} contradictory {evidence}. Educators now advocate for explicit instruction in {lateral} reading — verifying claims by consulting independent sources simultaneously — as a more {effective} strategy than traditional fact-checking. Building a digitally {literate} citizenry is no longer optional; it is a {prerequisite} for a functioning {democracy}.',
  options:['evaluate','competency','distinguish','legitimate','bubbles','reinforce','excluding','evidence','lateral','effective','literate','prerequisite','democracy','ignorant','passive','biased','misleading','trusted']},

 {id:312,title:'The Science of Well-Being',level:'İleri',
  text:'Positive psychology, pioneered by Martin Seligman, shifted the field\'s focus from {pathology} to the study of human {flourishing}. Seligman\'s PERMA model identifies five pillars of well-being: positive {emotions}, engagement, positive relationships, {meaning}, and achievement. Crucially, research consistently demonstrates that well-being is not primarily a function of material {wealth} beyond a moderate income threshold. Instead, {autonomy} — the sense of control over one\'s own life — and social {connectedness} emerge as the strongest {predictors} of long-term {happiness}. Longitudinal studies further confirm that the quality of close relationships is the single greatest {determinant} of a fulfilling life, {surpassing} career success and physical health as a predictor of late-life satisfaction.',
  options:['pathology','flourishing','emotions','meaning','wealth','autonomy','connectedness','predictors','happiness','determinant','surpassing','miserable','isolated','material','passive','shallow','broken','empty']},

 {id:114,title:'My Morning Routine',level:'Kolay',
  text:'Every morning, Maya wakes up at seven o\'clock. She {stretches} in bed for a few minutes before getting up. Then she goes to the bathroom and {brushes} her teeth. After that, she has a {shower} and gets dressed. She eats a {bowl} of cereal with milk for breakfast. Before leaving the house, she checks her {bag} to make sure she has everything. She walks to the bus stop and {waits} for the number twelve bus. She always {arrives} at work on time. Maya says a good morning routine makes the whole {day} better.',
  options:['stretches','brushes','shower','bowl','bag','waits','arrives','day','sleeps','rushed','skips','late','forgot','evening']},

 {id:115,title:'The New Puppy',level:'Kolay',
  text:'Last weekend, the Chen family got a new {puppy}. They named him Biscuit because of his golden {colour}. At first, Biscuit was {shy} and hid under the sofa. The children sat quietly on the floor and waited for him to come out. Slowly, Biscuit began to {explore} the house. He sniffed everything and {wagged} his tail when he found his new {bed}. That night, he cried a little, but the children stayed close to {comfort} him. By morning, Biscuit was already part of the {family}.',
  options:['puppy','colour','shy','explore','wagged','bed','comfort','family','aggressive','lost','ignored','barked','scared','old']},

 {id:116,title:'A Rainy Day',level:'Kolay',
  text:'It was raining heavily outside. Zoe had planned to go to the park, but she had to {stay} indoors. Instead, she decided to {bake} some cookies with her grandmother. They mixed {butter}, sugar, and {flour} together in a big bowl. Zoe {stirred} the mixture slowly. Grandma showed her how to cut the cookies into different {shapes}. They put them in the {oven} and waited. When the cookies were ready, the whole house smelled {wonderful}. Zoe forgot all about the {rain}.',
  options:['stay','bake','butter','flour','stirred','shapes','oven','wonderful','rain','boring','ruined','outside','mud','cold']},

 {id:117,title:'The Birthday Party',level:'Kolay',
  text:'It was Lila\'s eighth {birthday}. Her mum had decorated the house with {balloons} and colourful streamers. Ten friends came to the {party}. They played games in the garden and {laughed} a lot. Then Lila\'s dad brought out the {cake}. It had eight candles on it. Everyone sang happy birthday, and Lila blew out all the {candles} in one breath. She {opened} her presents one by one. Her favourite gift was a set of {painting} supplies. It was the best birthday she had ever {had}.',
  options:['birthday','balloons','party','laughed','cake','candles','opened','painting','had','boring','forgotten','cried','alone','noisy']},

 {id:118,title:'At the Supermarket',level:'Kolay',
  text:'Sam\'s mum sent him to the supermarket with a {list} of things to buy. He needed {bread}, milk, eggs, and some {fruit}. Sam pushed the {trolley} around the store, checking off each item. He almost forgot the {eggs} but remembered at the last moment. At the checkout, he {counted} his money carefully. He had just enough. The cashier {smiled} and gave him his {change}. Sam walked home feeling very {proud} that he had done the shopping all by himself.',
  options:['list','bread','fruit','trolley','eggs','counted','smiled','change','proud','lost','forgot','empty','confused','angry']},

 {id:119,title:'My Favourite Season',level:'Kolay',
  text:'Ben\'s favourite season is {autumn}. He loves the way the leaves {turn} red, orange, and yellow. Every weekend, he and his dad go for long {walks} in the woods. They kick the {leaves} on the ground and listen to them crunch. Sometimes they {collect} interesting leaves and press them in a book. Ben also loves the smell of {bonfires} in the evening. At home, he drinks hot {chocolate} and reads by the window. He thinks autumn is the most {beautiful} time of year.',
  options:['autumn','turn','walks','leaves','collect','bonfires','chocolate','beautiful','boring','winter','hot','noisy','busy','quiet']},

 {id:120,title:'The School Trip',level:'Kolay',
  text:'On Monday, Class 4B went on a school {trip} to the science museum. Everyone was very {excited} on the bus. At the museum, a guide showed them how {planets} move around the sun. They watched a short film inside a big round {dome}. Mia\'s favourite part was the room where you could touch {fossils} and real {rocks}. They had their {lunch} in the museum café. On the way back, everyone was tired but {happy}. Mia said she wanted to become a {scientist} one day.',
  options:['trip','excited','planets','dome','fossils','rocks','lunch','happy','scientist','boring','scared','lost','angry','late']},

 {id:121,title:'A Surprise Gift',level:'Kolay',
  text:'One afternoon, there was a {knock} at the door. When Anna opened it, she found a small {package} on the step. There was no name on it. Inside the package was a beautiful {scarf} in her favourite colour, blue. There was a small {note} that said, "From a friend who cares." Anna had no idea who had sent it. She asked her neighbours, but nobody {knew}. That evening, her sister finally {admitted} she had left it. Anna {hugged} her and said it was the most {thoughtful} gift she had ever received.',
  options:['knock','package','scarf','note','knew','admitted','hugged','thoughtful','mean','forgotten','ignored','angry','empty','noisy']},

 {id:122,title:'The Bakery',level:'Kolay',
  text:'Every Saturday morning, Rosa goes to the small {bakery} on the corner of her street. The baker, Mr. Filip, always has fresh bread ready by eight o\'clock. Rosa loves the smell of the warm {oven} as soon as she walks through the {door}. She usually buys a loaf of sourdough bread and two {croissants}. Sometimes Mr. Filip gives her a small piece of cake to try for {free}. Rosa always stops to {chat} with him for a few minutes. She says the bakery feels like the {heart} of the neighbourhood.',
  options:['bakery','oven','door','croissants','free','chat','heart','noisy','closed','empty','rushed','plain','cold','busy']},

 {id:123,title:'Making Friends',level:'Kolay',
  text:'On his first day at the new school, Kai felt very {nervous}. He did not know anyone and sat {alone} at lunch. Then a girl named Priya sat next to him and {smiled}. She asked him where he was from. They {talked} for a long time about their favourite films and {games}. After lunch, Priya introduced him to her other {friends}. By the end of the day, Kai already had a {group} to walk home with. He realised that making friends was {easier} than he had thought. He could not wait to come back to {school} the next day.',
  options:['nervous','alone','smiled','talked','games','friends','group','easier','school','ignored','scared','silent','cried','shy']},

 {id:124,title:'The Park',level:'Kolay',
  text:'Every evening after dinner, the Williams family goes to the {park} near their house. The children run to the {swings} and take turns pushing each other. Their dog, Max, {chases} squirrels through the grass. Mum and Dad walk along the {path} and talk about their day. Sometimes they stop to {feed} the ducks at the {pond}. When it gets dark, Dad calls everyone {together}. They walk home slowly, tired and {happy}. The park is their favourite place to {relax} as a family.',
  options:['park','swings','chases','path','feed','pond','together','happy','relax','busy','loud','stayed','bored','rushed']},

 {id:125,title:'A Phone Call',level:'Kolay',
  text:'Grandma lives far away, so Sophie {calls} her every Sunday. They always talk for at least an {hour}. Grandma tells Sophie about her {garden} and what she has been cooking. Sophie tells her about school and her {friends}. Last week, Sophie read a {poem} she had written herself. Grandma listened carefully and said it was {wonderful}. Sometimes they play a simple {word} game over the phone. Sophie always feels {warm} and happy after talking to her grandmother. She counts the {weeks} until she can visit in person.',
  options:['calls','hour','garden','friends','poem','wonderful','word','warm','weeks','forgot','silent','bored','short','angry']},

 {id:126,title:'The Garden',level:'Kolay',
  text:'Mr. Ali spends every morning in his {garden}. He grows tomatoes, cucumbers, and many different {herbs}. He gets up early to {water} the plants before the sun gets too hot. He pulls out the {weeds} by hand. His daughter sometimes helps him {dig} new beds for planting. Mr. Ali says that gardening teaches you to be {patient} because plants grow slowly. At the end of summer, the family uses his {vegetables} to make big, delicious meals. The garden gives Mr. Ali a great sense of {pride}.',
  options:['garden','herbs','water','weeds','dig','patient','vegetables','pride','lazy','bought','busy','noisy','failed','cement']},

 {id:127,title:'On the Bus',level:'Kolay',
  text:'Every morning, Clara takes the {bus} to college. She always sits in the same {seat} near the window. On the bus, she {reads} or listens to music. One morning, she noticed an old man {standing} because there were no empty seats. Clara immediately {stood} up and offered him her {place}. The old man thanked her with a big {smile}. The other passengers saw this and some of them also {moved} to help. Clara felt a quiet sense of {pride} as she held the rail and looked out of the window.',
  options:['bus','seat','reads','standing','stood','place','smile','moved','pride','ignored','rushed','angry','late','walked']},

 {id:128,title:'The Art Class',level:'Kolay',
  text:'Every Thursday, Leo goes to an art {class} at the community centre. The teacher shows the students different {techniques} each week. This week they learned how to {mix} colours to create new {shades}. Leo discovered that mixing blue and yellow makes {green}. He spent an hour painting a {landscape} of the mountains near his town. At the end of the class, everyone {displayed} their work on the wall. Leo was a little {embarrassed} at first, but the others said his painting was {beautiful}. He left feeling very {inspired}.',
  options:['class','techniques','mix','shades','green','landscape','displayed','embarrassed','beautiful','inspired','boring','failed','copied','wrong']},

 {id:129,title:'A Sick Day',level:'Kolay',
  text:'One morning, Ella woke up with a sore {throat} and a headache. Her mum took her {temperature} and said she had a slight {fever}. Ella had to stay home from school. Her mum made her a cup of warm {tea} with honey and lemon. Ella lay on the sofa and watched her favourite {show}. Her little brother brought her his favourite {toy} to cheer her up. By the afternoon, she was feeling a little {better}. The next morning, she was well enough to go back to school.',
  options:['throat','temperature','fever','tea','show','toy','better','tired','bored','cried','cold','rested','alone','weak']},

 {id:130,title:'The New Teacher',level:'Kolay',
  text:'The first day back at school after the holidays, Class 5 had a new {teacher}. Her name was Miss Okafor. She had a {warm} smile and spoke in a calm, clear {voice}. Instead of starting with a {lesson}, she asked each student to share one interesting fact about themselves. Some students were {shy} at first, but soon everyone was talking and {laughing}. Miss Okafor listened to every student {carefully}. At the end of the day, the class agreed that this year would be {different}. Even the quietest students felt {welcome}.',
  options:['teacher','warm','voice','lesson','shy','laughing','carefully','different','welcome','strict','scared','boring','lonely','quiet']},

 {id:214,title:'The Job Interview',level:'Orta',
  text:'Marta had been preparing for her job {interview} for two weeks. She had researched the {company} thoroughly and practised answering common {questions}. On the day, she wore her smartest {outfit} and arrived fifteen minutes {early}. The interviewer was {friendly} and asked her about her previous experience and long-term {goals}. Marta spoke clearly and gave {specific} examples from her past work. She also asked two thoughtful questions about the company\'s {culture}. A week later, she received an email {offering} her the position. All the hard work had paid {off}.',
  options:['interview','company','questions','outfit','early','friendly','goals','specific','culture','offering','off','unprepared','nervous','failed','late']},

 {id:215,title:'A Weekend Project',level:'Orta',
  text:'Daniel had been wanting to build a bookshelf for his home {office} for months. One Saturday morning, he finally bought the wood and {tools} he needed. He watched several online {tutorials} before starting. The first step was to {measure} each piece carefully. He learned the hard way that cutting a piece {short} meant starting again. After eight hours of {work}, the bookshelf was finally standing. It was not {perfect} — one shelf was slightly {uneven} — but it was his. Daniel {loaded} it with his books and stood back to {admire} his work.',
  options:['office','tools','tutorials','measure','short','work','perfect','uneven','loaded','admire','bought','lazy','gave','broken']},

 {id:216,title:'The Online Business',level:'Orta',
  text:'Last year, Chloe started an online business {selling} handmade jewellery. She set up a simple {website} and opened accounts on several {platforms}. At first, orders were very {slow}. She posted regularly on social media, showing how each piece was {made}. Gradually, her {audience} grew. One photo of a silver {necklace} went viral and she received over two hundred orders in a single {weekend}. She had to work every evening for a month to {fulfil} them all. The experience taught her about both the {rewards} and the {pressures} of running a small business.',
  options:['selling','website','platforms','slow','made','audience','necklace','weekend','fulfil','rewards','pressures','quit','failed','easy','offline']},

 {id:217,title:'The Road Trip',level:'Orta',
  text:'Three friends decided to drive across the country for two {weeks}. They planned a rough {route} but left plenty of room for {detours}. On the first day, they got {lost} in a small mountain town with no phone signal. Instead of panicking, they stopped at a local café and asked for {directions}. The owner invited them to stay for dinner and told them about a hidden {waterfall} nearby. It turned out to be the most {memorable} part of the whole trip. The best {adventures}, they agreed, are never fully {planned}.',
  options:['weeks','route','detours','lost','directions','waterfall','memorable','adventures','planned','rushed','straight','boring','broken','cancelled']},

 {id:218,title:'Learning to Cook',level:'Orta',
  text:'When Tariq moved into his own apartment, he realised he could barely {cook}. He had always relied on ready meals and takeaways. He decided to {challenge} himself to cook something new every week. He started with simple {dishes} — scrambled eggs, pasta, and soup. He quickly learned that {seasoning} was the most important part of any recipe. He began watching cooking shows and experimenting with {spices}. After three months, he could confidently prepare a full {dinner} for friends. Cooking, he discovered, was not just about food — it was a way of showing people he {cared}.',
  options:['cook','challenge','dishes','seasoning','spices','dinner','cared','failed','ordered','burnt','avoided','skipped','plain','hungry']},

 {id:219,title:'The Book Club',level:'Orta',
  text:'When Rosa moved to a new town, she joined the local {book} club to meet people. The club met on the first Friday of every {month} at the public library. Members took turns {choosing} the book. Rosa chose a novel set in 1920s Istanbul, which everyone enjoyed. The discussions were always {lively}. People did not always {agree} — some argued passionately about the ending of one book for over an {hour}. Rosa loved how books could {spark} such deep conversations. She also made three close {friends} through the club. Reading, she found, was never truly a {solitary} activity.',
  options:['book','month','choosing','lively','agree','hour','spark','friends','solitary','boring','stopped','quiet','empty','alone']},

 {id:220,title:'A Career Change',level:'Orta',
  text:'After fifteen years as an accountant, Patrick decided he was not {happy}. He had always had a passion for {woodworking} but had never pursued it seriously. He enrolled in a part-time {course} and started making furniture in his {garage} at weekends. Friends began asking him to make pieces for their {homes}. He saved up enough money to take six months {off} work. During that time, he built and sold enough furniture to prove the idea was {viable}. At forty-two, he handed in his {resignation} and never looked {back}. He says it was the bravest {decision} he ever made.',
  options:['happy','woodworking','course','garage','homes','off','viable','resignation','back','decision','easy','failed','regret','boring']},

 {id:221,title:'The Music Festival',level:'Orta',
  text:'Every summer, thousands of people travel to the valley for the three-day {festival}. This year, Sasha was going for the first time. She had bought her {ticket} six months in advance. She packed a tent, a sleeping {bag}, and enough snacks for the whole {weekend}. The first night, she watched her favourite {band} play on the main stage. The crowd was enormous and full of {energy}. During the day, she explored smaller {stages} and discovered three new artists she had never heard of before. By Sunday evening, her feet were sore, her voice was {hoarse}, and she was absolutely {exhausted}. She started planning for next year on the drive home.',
  options:['festival','ticket','bag','weekend','band','energy','stages','hoarse','exhausted','missed','boring','alone','cancelled','quiet']},

 {id:222,title:'Dealing with Stress',level:'Orta',
  text:'When the deadline for her final project arrived, Nina felt completely {overwhelmed}. She was not sleeping well and had been skipping {meals}. Her flatmate noticed and sat down with her for a {talk}. She suggested that Nina break the project into smaller {tasks} and tackle one at a time. Nina also started going for a twenty-minute {walk} each morning to clear her head. She turned off her phone for two hours each evening to reduce {distractions}. Within a week, she felt more in {control}. The project was submitted on time. The experience taught her that managing stress is a {skill} worth {practising}.',
  options:['overwhelmed','meals','talk','tasks','walk','distractions','control','skill','practising','failed','collapsed','ignored','panic','rushed']},

 {id:223,title:'The Community Garden',level:'Orta',
  text:'A disused car park in the centre of town had sat empty for years. A group of {residents} decided to transform it into a community {garden}. They raised money through a crowdfunding {campaign} and received a small grant from the local {council}. Over one busy weekend, volunteers {cleared} the space and built raised beds. Each family that {contributed} received a plot to grow their own food. The garden quickly became a place where neighbours began to {connect}. Children learned where {vegetables} actually come from. By autumn, the harvest was enough to share with the whole {street}.',
  options:['residents','garden','campaign','council','cleared','contributed','connect','vegetables','street','abandoned','failed','refused','empty','destroyed']},

 {id:224,title:'A Travel Adventure',level:'Orta',
  text:'When Yuki arrived in Morocco alone, she spoke neither Arabic nor French. She had only a {guidebook} and a small {backpack}. On her first day, she got completely {lost} in the medina. Instead of panicking, she {accepted} the confusion as part of the adventure. A young woman noticed her and offered to {help}. She showed Yuki around for the rest of the afternoon and invited her to her family\'s home for {dinner}. The experience reminded Yuki that {kindness} exists everywhere and that not knowing the {language} is not the same as not being able to {communicate}.',
  options:['guidebook','backpack','lost','accepted','help','dinner','kindness','language','communicate','panicked','ignored','tourist','rushed','alone']},

 {id:225,title:'The Study Group',level:'Orta',
  text:'Exam season was approaching, and four students from the {economics} course decided to form a study {group}. They met in the library every Tuesday and Thursday. At first, they spent more time chatting than studying, but eventually they established ground {rules}: phones away, one topic per session, and everyone must {contribute}. They discovered that {explaining} concepts to each other was more effective than reading alone. When one person {struggled}, the others helped until everyone understood. All four students passed their {exams} with stronger results than the previous {year}. They agreed that {collaboration} had made the difference.',
  options:['economics','group','rules','contribute','explaining','struggled','exams','year','collaboration','failed','alone','cheated','skipped','silent']},

 {id:226,title:'Starting Over',level:'Orta',
  text:'At the age of thirty-five, Sofia found herself in a very difficult {situation}. She had recently lost her job and was going through major personal changes. She moved into a small flat and took a night-school {course} in graphic design. During the day, she looked after her children; in the evenings, she {studied}. After a year, she began taking on {freelance} work. Her client list grew {steadily}. Three years later, she had her own small {agency} with four members of staff. She is quick to tell others that starting over is not a sign of {failure} — it is a sign of {courage}.',
  options:['situation','course','studied','freelance','steadily','agency','failure','courage','alone','bitter','ashamed','helpless','broke','lost']},

 {id:227,title:'The Art Exhibition',level:'Orta',
  text:'Marco had been painting for twenty years but had always kept his work {private}. His daughter eventually {convinced} him to enter a local art {competition}. He submitted three {paintings} he had made during a long period of isolation — each one a different view of the empty {street} outside his window. To his {surprise}, one of the paintings won second {prize}. It was selected for a group {exhibition} at the city gallery. Standing in the gallery watching {strangers} admire his work, Marco felt something he had never felt before: the specific {joy} of being truly {seen}.',
  options:['private','convinced','competition','paintings','street','surprise','prize','exhibition','strangers','joy','seen','scared','embarrassed','rejected','ignored']},

 {id:228,title:'A Social Media Break',level:'Orta',
  text:'After years of constant scrolling, Jade decided to take a {break} from all social media for thirty days. The first three days were {difficult}. She kept reaching for her phone out of {habit}. By the end of the first week, she noticed she was {sleeping} better and feeling less {anxious}. She started reading again and spent more time {outdoors}. She called friends instead of liking their {posts}. When the thirty days were up, she did not rush to go {back}. She created new rules for herself: no phone in the {bedroom} and only thirty minutes of social media per day. The break had {reset} her relationship with technology.',
  options:['break','difficult','habit','sleeping','anxious','outdoors','posts','back','bedroom','reset','failed','boring','addicted','isolated']},

 {id:229,title:'The Mentor',level:'Orta',
  text:'When Amara started her first professional {job}, she felt lost in the large organisation. Her manager {assigned} her a mentor, an experienced colleague named Helen. Every two weeks, they met for {coffee} and talked openly about the {challenges} Amara was facing. Helen did not give her all the {answers} — instead, she asked questions that helped Amara think things through herself. She also introduced Amara to {contacts} across the organisation. Over time, Amara grew more {confident} and began taking on bigger {responsibilities}. Years later, Amara became a mentor herself, passing on what she had {learned}.',
  options:['job','assigned','coffee','challenges','answers','contacts','confident','responsibilities','learned','ignored','alone','failed','confused','lost']},

 {id:230,title:'Night School',level:'Orta',
  text:'Victor left school at sixteen to help {support} his family. For twenty years, he worked as a mechanic and never thought about going back to {education}. Then, at thirty-six, he {enrolled} in a night school accounting course. After a full day at the garage, he would drive to the {college} and sit in class for two hours. He was often tired, but the other {students} — many with similar stories — kept him {motivated}. Three years later, he passed his final {exams} with distinction. He now works as a {bookkeeper} for a local firm. He says it is never too {late} to begin {again}.',
  options:['support','education','enrolled','college','students','motivated','exams','bookkeeper','late','again','quit','failed','tired','gave']},

 {id:313,title:'The Ethics of Artificial Intelligence',level:'İleri',
  text:'The rapid development of artificial {intelligence} raises profound ethical questions that society has barely begun to {address}. Algorithmic systems now make or influence decisions in areas ranging from criminal {sentencing} to medical {diagnosis}. Critics highlight the risk of encoding existing social {biases} into automated systems, thereby {perpetuating} structural inequality at scale. A further concern is the question of {accountability}: when an algorithm makes a consequential {error}, it is rarely clear who bears {responsibility}. Proponents argue that AI, if properly {governed}, can reduce human {subjectivity} and improve {consistency}. Resolving these tensions requires interdisciplinary {collaboration} between technologists, ethicists, and {policymakers}.',
  options:['intelligence','address','sentencing','diagnosis','biases','perpetuating','accountability','error','responsibility','governed','subjectivity','consistency','collaboration','policymakers','perfect','neutral']},

 {id:314,title:'Urban Planning and the Future of Cities',level:'İleri',
  text:'As the global urban population continues to {expand}, city planners face the dual challenge of providing {adequate} infrastructure while minimising {environmental} impact. The concept of the fifteen-minute city — in which all essential {amenities} are reachable on foot within fifteen minutes — has gained significant {traction} among planners worldwide. By reducing {dependence} on private cars, such models can {alleviate} traffic {congestion} and substantially lower {emissions}. Critics, however, warn that without careful policy design, these initiatives risk {displacing} lower-income residents through property {gentrification}. Genuinely {inclusive} urban planning must therefore prioritise affordable housing alongside green infrastructure, ensuring that the benefits of {sustainable} cities are shared {equitably}.',
  options:['expand','adequate','environmental','amenities','traction','dependence','alleviate','congestion','emissions','displacing','gentrification','inclusive','sustainable','equitably','unchanged','polluted']},

 {id:315,title:'The Philosophy of Free Will',level:'İleri',
  text:'The question of whether human beings possess genuine free will remains one of philosophy\'s most {enduring} and contentious debates. Hard {determinists} argue that every event, including human {decisions}, is the inevitable result of prior causes governed by natural {laws}. If this is true, {moral} responsibility becomes philosophically {problematic}: how can we hold individuals {accountable} for actions they could not have chosen otherwise? Compatibilists attempt to {reconcile} determinism with moral responsibility by redefining freedom not as the absence of {causation} but as the absence of {coercion}. The debate has direct {implications} for how legal systems should approach concepts of punishment and {rehabilitation}.',
  options:['enduring','determinists','decisions','laws','moral','problematic','accountable','reconcile','causation','coercion','implications','rehabilitation','inevitable','random','simple','fixed']},

 {id:316,title:'Climate Grief',level:'İleri',
  text:'As the evidence of climate change becomes increasingly impossible to ignore, psychologists have begun documenting a distinct emotional response known as climate {grief}. This refers to the chronic {fear}, sadness, and sense of {loss} experienced in response to environmental {destruction} and an uncertain {future}. Unlike conventional anxiety, which is typically treated as a disorder, climate grief is increasingly recognised as a {rational} response to a genuine {threat}. Researchers note that young people are disproportionately {affected}, partly because they face a longer {exposure} to future consequences. Mental health practitioners are developing new {frameworks} that acknowledge both the validity of the distress and the importance of channelling it into {meaningful} action.',
  options:['grief','fear','loss','destruction','future','rational','threat','affected','exposure','frameworks','meaningful','imaginary','harmless','hopeful','denied']},

 {id:317,title:'Behavioural Economics',level:'İleri',
  text:'Classical economics {assumed} that individuals always act rationally, maximising utility based on complete {information}. Behavioural economics, pioneered by Daniel Kahneman and Amos Tversky, fundamentally {challenged} this model by demonstrating that human decision-making is systematically {biased}. The {anchoring} effect shows that people rely heavily on the first piece of information they encounter when making {judgements}. Loss {aversion} — the tendency to fear losses more strongly than we value equivalent gains — explains many seemingly {irrational} financial decisions. Governments now apply these {insights} through nudge {policy}, designing choice architectures that guide citizens towards {beneficial} decisions without restricting {freedom}.',
  options:['assumed','information','challenged','biased','anchoring','judgements','aversion','irrational','insights','policy','beneficial','freedom','perfect','logical','unchanged','equal']},

 {id:318,title:'The Future of Work',level:'İleri',
  text:'The convergence of {automation}, artificial intelligence, and remote working technologies is fundamentally {reshaping} the global labour market. Routine cognitive and manual {tasks} are increasingly susceptible to {displacement} by algorithms and {robotics}. Yet economists warn against purely pessimistic forecasts: historically, each wave of technological change has ultimately {generated} more employment than it {eliminated}, albeit in different sectors. The critical question is whether workers can {transition} quickly enough. Policymakers must {invest} heavily in lifelong learning {programmes} and portable benefits systems to support workers through periods of {disruption}. The future of work will reward adaptability and {resilience} — qualities that machines cannot yet {replicate}.',
  options:['automation','reshaping','tasks','displacement','robotics','generated','eliminated','transition','invest','programmes','disruption','resilience','replicate','unchanged','easy','instant']},

 {id:319,title:'Epigenetics and the Environment',level:'İleri',
  text:'Epigenetics is the study of changes in {gene} expression that do not involve alterations to the underlying DNA {sequence}. Instead, environmental {factors} such as diet, stress, and exposure to toxins can {modify} the chemical tags that sit on the genome, effectively switching genes on or {off}. This discovery has profoundly {challenged} the long-held assumption that our genetic fate is entirely {fixed} at birth. Research has shown that the {effects} of trauma can be {transmitted} across generations through epigenetic {mechanisms}. Conversely, positive {interventions} such as improved nutrition and reduced stress can {reverse} some of these modifications. Epigenetics thus offers a more {nuanced} understanding of the interaction between nature and nurture.',
  options:['gene','sequence','factors','modify','off','challenged','fixed','effects','transmitted','mechanisms','interventions','reverse','nuanced','determined','permanent','stable']},

 {id:320,title:'Media and Democracy',level:'İleri',
  text:'A functioning democracy depends on citizens having access to {accurate} and diverse {information}. When media ownership is concentrated in the hands of a few powerful {corporations}, the range of {perspectives} available to the public inevitably {narrows}. The rise of partisan online media has {exacerbated} this problem, as platforms use algorithmic {curation} to show users content that {reinforces} their existing beliefs. This creates a fragmented public {sphere} in which citizens inhabit entirely different informational {realities}. Rebuilding shared {epistemic} ground requires both regulatory {intervention} and investment in public media that operates free from both {commercial} and political {interference}.',
  options:['accurate','information','corporations','perspectives','narrows','exacerbated','curation','reinforces','sphere','realities','epistemic','intervention','commercial','interference','biased','uniform']},

 {id:321,title:'The Attention Economy',level:'İleri',
  text:'The business model of most major digital {platforms} is built on the {commodification} of human attention. The longer a user remains {engaged}, the more data is collected and the more {advertising} revenue is generated. Platform designers employ a range of techniques — infinite scroll, variable reward {notifications}, and social {validation} signals — drawn directly from behavioural psychology to maximise {engagement}. Critics argue that this model is fundamentally {incompatible} with human wellbeing and democratic {discourse}, as it systematically {prioritises} outrage and emotional arousal over accurate information. Several jurisdictions have begun considering legislative {restrictions} on design features deemed psychologically {manipulative}, particularly as they relate to children.',
  options:['platforms','commodification','engaged','advertising','notifications','validation','engagement','incompatible','discourse','prioritises','restrictions','manipulative','healthy','neutral','balanced','passive']},

 {id:322,title:'Cultural Memory',level:'İleri',
  text:'Cultural memory refers to the collective {framework} through which societies record, interpret, and transmit {knowledge} about their past. Unlike individual memory, it is not stored biologically but is inscribed in {monuments}, rituals, texts, and institutional {practices}. The sociologist Jan Assmann argued that cultural memory serves to anchor a group\'s sense of {identity} by connecting the present to a {meaningful} origin narrative. However, cultural memory is never {neutral}: it is always shaped by those with the power to {determine} which events are commemorated and which are {forgotten}. Debates about {statues}, museums, and national {curricula} are, at their core, struggles over whose version of the past should define collective {heritage}.',
  options:['framework','knowledge','monuments','practices','identity','meaningful','neutral','determine','forgotten','statues','curricula','heritage','objective','permanent','fixed','shared']},

 {id:323,title:'The Science of Sleep',level:'İleri',
  text:'Sleep was long regarded as a passive state — a mere {absence} of wakefulness. Neuroscientific research has {overturned} this view, revealing sleep to be a period of intense biological {activity}. During the deepest stages of sleep, the brain\'s glymphatic system {flushes} out metabolic waste products, including proteins {associated} with neurodegenerative disease. Rapid eye movement sleep plays a critical role in emotional {regulation} and memory {consolidation}. Research demonstrates that chronic sleep {deprivation} impairs cognitive function more severely than most people {recognise}, affecting {judgement} and immune response. Despite this evidence, modern societies continue to {celebrate} productivity at the expense of sleep, treating rest as a sign of {weakness} rather than a biological {necessity}.',
  options:['absence','overturned','activity','flushes','associated','regulation','consolidation','deprivation','recognise','judgement','celebrate','weakness','necessity','optional','harmless','short']},

 {id:324,title:'Language and Thought',level:'İleri',
  text:'The relationship between language and {thought} is one of the most contested questions in {cognitive} science. The Sapir-Whorf {hypothesis} — also known as linguistic {relativity} — proposes that the language a person speaks shapes the way they {perceive} and conceptualise the world. Strong versions suggest that thought is impossible without language; weaker versions claim that language {influences} certain cognitive {patterns}. Evidence includes studies showing that speakers of languages with different {colour} terminology perceive colour distinctions differently. Critics argue that {universal} aspects of human cognition — such as spatial reasoning — operate largely {independently} of language. The debate remains {unresolved}, but it has profoundly shaped fields from {anthropology} to artificial intelligence.',
  options:['thought','cognitive','hypothesis','relativity','perceive','influences','patterns','colour','universal','independently','unresolved','anthropology','settled','identical','fixed','natural']},

 {id:325,title:'The Social Contract',level:'İleri',
  text:'The concept of the social {contract} is a foundational idea in political {philosophy}, associated with thinkers such as Hobbes, Locke, and Rousseau. Each theorist imagined a hypothetical state of nature — life before organised {society} — and asked what rational individuals would {agree} to in order to escape it. For Hobbes, the answer was an absolute {sovereign} capable of maintaining order. Locke emphasised the protection of natural {rights} — life, liberty, and {property}. Rousseau argued that true {freedom} could only be achieved through direct {participation} in the collective {will}. Contemporary political philosophy continues to draw on these {frameworks} to address questions of {legitimacy} and justice.',
  options:['contract','philosophy','society','agree','sovereign','rights','property','freedom','participation','will','frameworks','legitimacy','irrelevant','outdated','imposed','broken']},

 {id:326,title:'Quantum Computing',level:'İleri',
  text:'Classical computers process information as {bits} — binary units that can exist in one of two states: zero or one. Quantum computers, by contrast, use {qubits}, which exploit the principle of {superposition} to exist in multiple states {simultaneously}. This allows certain calculations to be performed {exponentially} faster than is possible with classical {hardware}. A further quantum property, {entanglement}, enables qubits to be correlated in ways that have no classical {equivalent}, amplifying computational power. Quantum computers are particularly promising for problems in {cryptography}, drug {discovery}, and materials science. However, they remain extremely {fragile}: qubits must be maintained at temperatures close to absolute zero to prevent {decoherence}.',
  options:['bits','qubits','superposition','simultaneously','exponentially','hardware','entanglement','equivalent','cryptography','discovery','fragile','decoherence','simple','stable','cheap','fast']},

 {id:327,title:'The Ethics of Consumption',level:'İleri',
  text:'Consumerism — the cultural {imperative} to acquire goods as a marker of {identity} and {status} — is a relatively recent historical {phenomenon}. Anthropologists trace its widespread emergence to the post-war era, when mass {production} created surplus goods that required new markets to {absorb}. Today, the environmental and ethical {consequences} of overconsumption are increasingly {apparent}. The fashion industry alone generates enormous volumes of {textile} waste and significant {carbon} emissions. The ethical consumer movement advocates for {conscious} purchasing decisions — buying less, buying locally, and choosing products made under fair {labour} conditions. Critics note, however, that framing sustainability as individual choice risks {obscuring} the systemic changes ultimately {required}.',
  options:['imperative','identity','status','phenomenon','production','absorb','consequences','apparent','textile','carbon','conscious','labour','obscuring','required','infinite','harmless']},

 {id:328,title:'The Power of Narrative',level:'İleri',
  text:'Humans are, at their core, {storytelling} animals. Long before the invention of writing, oral {narratives} served to transmit cultural knowledge, establish {moral} norms, and bind communities {together}. Cognitive scientists have shown that the brain processes information embedded in a story far more {effectively} than data presented in isolation. This is partly because stories {activate} multiple neural networks simultaneously — those associated with {language}, sensory experience, and emotion. Marketers, politicians, and social {movements} all exploit this property, using compelling stories to shape {attitudes} and {behaviour}. The capacity to construct and {deconstruct} narratives is therefore a critical skill — one that enables individuals to resist {manipulation} and engage more {critically} with the world around them.',
  options:['storytelling','narratives','moral','together','effectively','activate','language','movements','attitudes','behaviour','deconstruct','manipulation','critically','random','neutral','passive']},
];

